Reproduction:

```Python
import jedi

source = '''\
import re
from dateutil import parser
from dateutil.relativedelta import relativedelta
from datetime import datetime

MONTHS = ["January", "February", "March", "April", "May", "June", "July",
          "August", "September", "October", "November", "December"]
MONTH_INDICES = list([str(x).zfill(2) for x in range(1, len(MONTHS) + 1)])


def switch_numbers(v):
    digits = re.findall(r"\d+", v)
    return re.sub(r"\d+", "{}", v).format(*reversed(digits))


def replace_months(v):
    for num, month in zip(MONTH_INDICES, MONTHS):
        v = v.replace(month, num)
        v = v.replace(month.lower(), num)
    return v


def get_text_date(v, fuzzy=True):
    v = replace_months(v)
    try:
        extracted_date = parser.parse(v, fuzzy=fuzzy)
    except ValueError:
        extracted_date = parser.parse(switch_numbers(v), fuzzy=fuzzy)
    if extracted_date is not None:
        return extracted_date
    return False


def get_soon_date(v, fuzzy=True):
    start_date = datetime.now()
    end_date = start_date + relativedelta(years=3)
    extracted_date = get_text_date(v, fuzzy=True)
    try:
        ed = get_text_date(v, fuzzy=False)
    except Val:
        ed = False
    if start_date is not None and start_date > extracted_date:
        now = datetime.now()
        if extracted_date.month < now.month and extracted_date.year == now.year:
            extracted_date = extracted_date.replace(year=extracted_date.year + 1)
        else:
            return False
    if end_date is not None and end_date < extracted_date:
        return False
    return extracted_date


def get_tomorrow():
    return datetime.now() + relativedelta(days=1)

modifiers = [" ", ".+", "in", "this", "next"]  # "" and "in" is "this"
# zero or multi match
numbers = [" ", ".+", "\d+"]
units = ["day", "week", "month", "year"]


def token_sentence_matcher(sentence):
    if isinstance(sentence, str):
        sentence = sentence.split()
    m1 = []
    n = len(sentence)
    matches = []
    for t1, t2, t3 in time_regex_tokens:
        for i in range(n - 1):
            if not t1.search(sentence[i]):
                continue
            print(t1)
            if i + 1 >= n or not t2.search(sentence[i + 1]):
                continue
            print(t2)
            if t3 is not None:
                if i + 2 >= n or not t3.search(sentence[i + 2]):
                    continue
            matches.append([i, t1, t2, t3])
    return matches

time_regex_tokens = []
for m in modifiers:
    for n in numbers:
        if n in [" ", ".+"] and m in [" ", ".+"]:
            continue
        for u in units:
            tokens = [x for x in [m.lstrip(), n.strip(), u] if x]
            if len(tokens) == 2:
                tokens.append(None)
            time_regex_tokens.append([None if x is None else re.compile(x) for x in tokens])
'''

